mapper.select:
WITH genre_movies AS ( SELECT DISTINCT mg.movies_id FROM movie_genres mg JOIN movie_genres_list mgl ON mgl.genres_id = mg.genres_id
WHERE mgl.genres IN
#{genre}
), filtered_movies AS ( SELECT m.id, m.imdb_id, m.korean_title, m.poster_path, m.backdrop_path, m.overview FROM genre_movies gm JOIN movies m ON m.id = gm.movies_id JOIN titles_adult ta ON ta.tconst = m.imdb_id WHERE m.release_date >= STR_TO_DATE(CONCAT(#{releaseYear[0]}, '-01-01'), '%Y-%m-%d') AND m.release_date < DATE_ADD(STR_TO_DATE(CONCAT(#{releaseYear[1]}, '-01-01'), '%Y-%m-%d'), INTERVAL 1 YEAR)
AND ta.is_adult = 1
AND ta.is_adult = 0
AND m.original_language = 'ko'
AND m.original_language != 'ko'
) SELECT fm.id, fm.korean_title, fm.poster_path, fm.backdrop_path, fm.overview, r.averageRating, "movie" FROM filtered_movies fm JOIN ratings r ON r.tconst = fm.imdb_id WHERE r.averageRating BETWEEN #{rating[0]} AND #{rating[1]} ORDER BY r.numVotes DESC, r.averageRating DESC LIMIT 20
